mapper.select:
select temp.jb_user_name,temp.jb_nick_name,temp.user_department,temp.user_section,temp.now_date, SUM(temp.rest_num) rest_num,SUM(temp.work_num) work_num,SUM(temp.quantity) quantity from ( select b.id, b.jbUserName as jb_user_name, b.jbNickName as jb_nick_name, b.UserDepartment as user_department, b.UserSection as user_section, date_format ( b.StartTime, '%Y-%m' ) as now_date, SUM(case c.xxrbs when 1 then cast(b.reviewhours as DECIMAL(8,2)) else 0 end) rest_num, SUM(case c.xxrbs when 0 then cast(b.reviewhours as DECIMAL(8,2)) else 0 end) work_num, 0 as quantity from v_req_hrovertime_all_end b LEFT JOIN (SELECT c.rq,c.xxrbs FROM mobile_platform_normal.sys_kq_date c WHERE c.RQ > '2018-8-31'
and c.RQ between #{criteria.startDate,jdbcType=DATE} and #{criteria.endDate,jdbcType=DATE}
) c ON DATE_FORMAT(b.StartTime, '%Y-%m-%d') = c.rq where b.reviewhours <> ''
and b.StartTime between #{criteria.startDate,jdbcType=DATE} and #{criteria.endDate,jdbcType=DATE}
and b.jbUserName = RIGHT(LPAD(#{criteria.workCode,jdbcType=VARCHAR}, 6 , '0'), 6 )
and b.jbNickName like #{criteria.name,jdbcType=VARCHAR}
and RIGHT(LPAD(b.jbUserName, 6 , '0'), 6 ) in
#{item.workCard}
and RIGHT(LPAD(b.jbUserName, 6 , '0'), 6 ) in
#{item.workCard}
and b.jbUserName = 'notExit'
GROUP BY b.jbUserName, date_format ( b.StartTime, '%Y%m' ) union all SELECT vrhae.id, vrhae.UserName jb_user_name, vrhae.NickName jb_nick_name, vrhae.UserDepartment user_department, (select b.SectionOffice from sys_user_mes b WHERE vrhae.UserName = b.WorkCardNumber) user_section, DATE_FORMAT(vrhae.StartTime, '%Y-%m') now_date, 0 AS rest_num, 0 AS work_num, SUM( cast(vrhae.Number as DECIMAL(8,2))) quantity FROM v_req_hrleave_all_end vrhae WHERE LeaveType='调休'
and DATE_FORMAT(vrhae.StartTime, '%Y%m') = DATE_FORMAT(#{criteria.startDate,jdbcType=DATE}, '%Y%m')
and vrhae.UserName = RIGHT(LPAD(#{criteria.workCode,jdbcType=VARCHAR}, 6 , '0'), 4 )
and vrhae.NickName like #{criteria.name,jdbcType=VARCHAR}
and RIGHT(LPAD(vrhae.UserName, 6 , '0'), 6 ) in
#{item.workCard}
and RIGHT(LPAD(vrhae.UserName, 6 , '0'), 6 ) in
#{item.workCard}
and vrhae.UserName = 'notExit'
group by vrhae.UserName) as temp group by temp.jb_user_name,temp.now_date
